import{_ as o,o as r,c as e,ag as l}from"./chunks/framework.CeCiKVaq.js";const h=JSON.parse('{"title":"🎬 博客技术架构全解析","description":"","frontmatter":{"new_folder":"blog","title":"🎬 博客技术架构全解析","slug":"博客技术架构全解析","date":"2026-04-30T00:00:00.000Z"},"headers":[],"relativePath":"column/blog/index.md","filePath":"column/blog/index.md"}'),i={name:"column/blog/index.md"};function a(s,t,n,g,u,d){return r(),e("div",null,[...t[0]||(t[0]=[l('<hr><h1 id="🚀-博客技术架构全解析" tabindex="-1">🚀 博客技术架构全解析 <a class="header-anchor" href="#🚀-博客技术架构全解析" aria-label="Permalink to &quot;🚀 博客技术架构全解析&quot;">​</a></h1><p>本博客系统采用了一套极具性价比且性能卓越的现代化技术栈，实现了内容管理自动化、鉴权中转无缝化以及前端渲染极致化。</p><hr><h2 id="🛠️-核心框架与工具链" tabindex="-1">🛠️ 核心框架与工具链 <a class="header-anchor" href="#🛠️-核心框架与工具链" aria-label="Permalink to &quot;🛠️ 核心框架与工具链&quot;">​</a></h2><h3 id="_1-vitepress-静态站点生成器" tabindex="-1">1. VitePress (静态站点生成器) <a class="header-anchor" href="#_1-vitepress-静态站点生成器" aria-label="Permalink to &quot;1. VitePress (静态站点生成器)&quot;">​</a></h3><ul><li><strong>定位</strong>：由 Vite 驱动的 Vue 极简静态网站生成器。</li><li><strong>特性</strong>： <ul><li><strong>极致性能</strong>：基于 Vite 构建，拥有极快的热更新速度和首屏加载性能。</li><li><strong>Markdown 增强</strong>：支持在 Markdown 中直接编写 Vue 组件。</li><li><strong>现代渲染</strong>：生成静态 HTML 的同时，作为单页应用（SPA）在浏览器中运行。</li></ul></li></ul><h3 id="_2-decap-cms-内容管理系统" tabindex="-1">2. Decap CMS (内容管理系统) <a class="header-anchor" href="#_2-decap-cms-内容管理系统" aria-label="Permalink to &quot;2. Decap CMS (内容管理系统)&quot;">​</a></h3><ul><li><strong>定位</strong>：一个基于 Git 的开源内容管理系统。</li><li><strong>特性</strong>： <ul><li><strong>Git-based</strong>：所有通过后台发布的文章都会直接转化为仓库中的 <code>commit</code>，无需传统数据库。</li><li><strong>配置驱动</strong>：通过 <code>config.yml</code> 定义字段结构，支持复杂的嵌套列表和文件管理。</li><li><strong>实时预览</strong>：在浏览器端提供所见即所得的编辑体验。</li></ul></li></ul><h3 id="_3-cloudflare-worker-鉴权中转层" tabindex="-1">3. Cloudflare Worker (鉴权中转层) <a class="header-anchor" href="#_3-cloudflare-worker-鉴权中转层" aria-label="Permalink to &quot;3. Cloudflare Worker (鉴权中转层)&quot;">​</a></h3><ul><li><strong>定位</strong>：轻量级边缘计算平台。</li><li><strong>特性</strong>： <ul><li><strong>Serverless</strong>：作为 GitHub OAuth 鉴权的中间件，处理复杂的 Token 交换逻辑。</li><li><strong>零成本</strong>：利用免费额度实现稳定、安全的后台登录功能。</li><li><strong>全球加速</strong>：在靠近用户的边缘节点运行，响应速度极快。</li></ul></li></ul><h3 id="_4-github-actions-自动化部署" tabindex="-1">4. GitHub Actions (自动化部署) <a class="header-anchor" href="#_4-github-actions-自动化部署" aria-label="Permalink to &quot;4. GitHub Actions (自动化部署)&quot;">​</a></h3><ul><li><strong>定位</strong>：CI/CD 自动化流水线。</li><li><strong>特性</strong>： <ul><li><strong>全自动流程</strong>：每当仓库有新的 <code>push</code>（来自本地或 CMS 后台），自动触发构建脚本。</li><li><strong>静态托管</strong>：自动将编译后的静态文件部署至 GitHub Pages 供全球访问。</li></ul></li></ul><hr><h2 id="🏗️-系统架构图解" tabindex="-1">🏗️ 系统架构图解 <a class="header-anchor" href="#🏗️-系统架构图解" aria-label="Permalink to &quot;🏗️ 系统架构图解&quot;">​</a></h2><p>整个博客的运行逻辑可以拆解为以下三个核心链路：</p><ol><li><strong>内容录入链</strong>： <code>Decap CMS (浏览器) -&gt; Cloudflare Worker (鉴权) -&gt; GitHub Repo (源码存储)</code></li><li><strong>构建部署链</strong>： <code>GitHub Push -&gt; GitHub Actions (Vite 编译) -&gt; GitHub Pages (静态发布)</code></li><li><strong>用户访问链</strong>： <code>用户浏览器 -&gt; GitHub Pages (CDN) -&gt; 加载渲染好的 VitePress 页面</code></li></ol><hr><h2 id="🌟-为什么选择这套架构" tabindex="-1">🌟 为什么选择这套架构？ <a class="header-anchor" href="#🌟-为什么选择这套架构" aria-label="Permalink to &quot;🌟 为什么选择这套架构？&quot;">​</a></h2><p>对于追求极致体验的开发者来说，这套方案拥有以下不可比拟的优势：</p><ul><li><strong>零配置维护</strong>：完全脱离了传统服务器（Nginx/Node.js/Database）的繁琐运维。</li><li><strong>永久免费</strong>：利用 GitHub 和 Cloudflare 的免费额度，实现了零成本运行。</li><li><strong>高性能表现</strong>：借助本地高性能开发环境配合 Vite 的毫秒级响应，确保开发与访问流畅无比。</li><li><strong>数据安全</strong>：所有文章即代码，拥有完善的版本控制历史，无需担心数据库损坏。</li></ul><hr><p><em>本文档由 Zoro Blog 自动化发布系统生成。</em></p>',23)])])}const b=o(i,[["render",a]]);export{h as __pageData,b as default};
